import { range } from './array.functions.js';
import { parseD6String, rollD6, rollD66 } from './dice.functions.js';
import { capitalize } from './utils.functions.js';
export const rollFindValue = fv => {
  if (fv === 'None') return [];
  const piles = fv.split(';');
  return piles.map(pile => {
    const [dice, coin] = pile.split(' ');
    const numberOfD6ToRoll = parseD6String(dice);
    const coinValue = range(numberOfD6ToRoll).map(_ => rollD6()).reduce((a, b) => a + b, 0);
    const coinLabel = `Coin.${capitalize(coin)}`;
    return {
      coins: coinValue,
      label: coinLabel
    };
  });
};
export const getRandomFind = findTable => {
  const roll = rollD66();
  const adjustedRoll = roll < 31 ? 31 : roll;
  return findTable[adjustedRoll];
};
const weightToViewModelDict = {
  0: 'None',
  0.25: 'Tiny',
  0.5: 'Light',
  1: 'Normal',
  2: 'Heavy',
  3: '3',
  4: '4',
  5: '5',
  6: '6',
  7: '7',
  8: '8'
};
export const createFindViewModel = f => {
  return { ...f,
    weight: weightToViewModelDict[f.weight],
    value: rollFindValue(f.value)
  };
};